            scope_id: "test".into(),
            source_version: "v1".into(),
        }
    }

    #[test]
    fn test_toml_section_splitting() {
        let source = "[package]\nname = \"test\"\nversion = \"0.1.0\"\n\n[dependencies]\nserde = \"1\"\ntokio = \"1\"\n";
        let chunker = ConfigChunker::new();
        let chunks = chunker.chunk(source, &toml_meta()).unwrap();
        assert!(chunks.len() >= 2, "expected at least 2 TOML sections, got {}", chunks.len());
        assert!(chunks[0].content.contains("[package]"));
        assert!(chunks.iter().any(|c| c.content.contains("[dependencies]")));
    }
